import usePollUntil from '@otovo/shared/hooks/usePollUntil';
import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import useSWR from 'swr';

async function fetcher(url: string) {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error();
  }

  return response.json();
}

const defaultPollUntil = () => true;

type UseInterestOptions = {
  pollUntilFunction?: (arg: Cloud$Interest) => boolean;
};

export default function useInterest(
  interestId: string,
  { pollUntilFunction = defaultPollUntil }: UseInterestOptions | undefined = {},
) {
  const url = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interestId}/`;
  const { data, error, mutate } = useSWR<Cloud$Interest>(url, fetcher);
  const { isPolling, isPollTimeout } = usePollUntil<Cloud$Interest>({
    data,
    pollFunction: mutate,
    pollUntilFunction,
  });

  return {
    interest: data,
    isFetchingInterest: !error && !data,
    fetchInterestError: error,
    isPolling,
    isPollTimeout,
    mutate,
  };
}
```


If we get 500 from the server, SWR should stop.
Currently, when a 500 error occurs, the fetcher throws a generic Error, but SWR will continue retrying by default. To make SWR stop retrying on a 500 error, you can modify the code in a few ways:

Here's one solution:

```ts
import usePollUntil from '@otovo/shared/hooks/usePollUntil';
import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import useSWR from 'swr';

async function fetcher(url: string) {
  const response = await fetch(url);
  if (!response.ok) {
    // Create an error object with the status code
    const error = new Error('API Error');
    (error as any).status = response.status;
    throw error;
  }

  return response.json();
}

const defaultPollUntil = () => true;

type UseInterestOptions = {
  pollUntilFunction?: (arg: Cloud$Interest) => boolean;
};

export default function useInterest(
  interestId: string,
  { pollUntilFunction = defaultPollUntil }: UseInterestOptions | undefined = {},
) {
  const url = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interestId}/`;
  const { data, error, mutate } = useSWR<Cloud$Interest>(url, fetcher, {
    // Don't retry on 500 errors
    shouldRetryOnError: (error) => (error as any).status !== 500,
  });

  const { isPolling, isPollTimeout } = usePollUntil<Cloud$Interest>({
    data,
    pollFunction: mutate,
    pollUntilFunction,
  });

  return {
    interest: data,
    isFetchingInterest: !error && !data,
    fetchInterestError: error,
    isPolling,
    isPollTimeout,
    mutate,
  };
}
```

Key changes made:
1. Modified the fetcher to include the status code in the thrown error
2. Added `shouldRetryOnError` configuration to SWR that checks the error status and prevents retrying if it's 500

This way, when a 500 error occurs, SWR will stop retrying and the error will be available through the `fetchInterestError` return value.

If you want to handle other server errors similarly, you could expand the `shouldRetryOnError` condition to include other status codes as well.
