```ts
import usePollUntil from '@otovo/shared/hooks/usePollUntil';
import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import useSWR from 'swr';

async function fetcher(url: string) {
  const response = await fetch(url);
  if (!response.ok) {
    const error = new Error('API Error');
    (error as any).status = response.status;
    throw error;
  }

  return response.json();
}

const defaultPollUntil = () => true;

type UseInterestOptions = {
  pollUntilFunction?: (arg: Cloud$Interest) => boolean;
};

export default function useInterest(
  interestId: string,
  { pollUntilFunction = defaultPollUntil }: UseInterestOptions | undefined = {},
) {
  const url = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interestId}/`;
  const { data, error, mutate } = useSWR<Cloud$Interest>(url, fetcher, {
    // Don't retry on any server errors (500-599)
    shouldRetryOnError: (error) => (error as any).status < 500,
  });

  const { isPolling, isPollTimeout } = usePollUntil<Cloud$Interest>({
    data,
    pollFunction: mutate,
    pollUntilFunction,
  });

  return {
    interest: data,
    isFetchingInterest: !error && !data,
    fetchInterestError: error,
    isPolling,
    isPollTimeout,
    mutate,
  };
}
```

Now SWR will:
- Continue retrying on client errors (400-499) as these might be temporary or fixable
- Stop retrying on any server errors (500-599) as these indicate server-side problems
- This is a better approach because server errors typically require intervention and won't be resolved by client retries.
